custom_css:
/*
 * 主题：午夜金星 (Midnight Gold Stars) — 暗色夜读升级版
 * 原作者：KAKAA | Discord: @rech0_viixi | 社区：类脑ΟΔΥΣΣΕΙΑ
 * 暗色重制 / 美学与性能升级：基于 ui-ux-pro-max「Dark Mode (OLED) + Glassmorphism」
 * 许可协议：CC BY-NC-SA 4.0 — 二改分享需注明原作者，禁止任何形式商用及商用引流。
 */

/* ==========================================================================
   1. 字体与基础设置
   ========================================================================== */
@import url("https://fontsapi.zeoseven.com/419/main/result.css");

body {
    font-family: "ToneOZ-Tsuipita-TC", "Noto Serif SC", serif;
    font-weight: normal;
    color-scheme: dark;
    text-rendering: optimizeLegibility;
}

/* ==========================================================================
   2. 全局变量配置（夜读暗色 + 星河金辉）
   ========================================================================== */
:root {
    /* 主题强调色：来自酒馆 SmartTheme（quote=金 / underline=星蓝） */
    --theme-color-1: var(--SmartThemeQuoteColor);
    --theme-color-2: var(--SmartThemeUnderlineColor);

    /* 暗色玻璃表面（夜读优化，深空蓝调，避免纯黑刺眼） */
    --surface-1: rgba(18, 23, 43, 0.86);   /* 主面板/消息底 */
    --surface-2: rgba(33, 40, 68, 0.92);   /* 输入框/按钮等抬升层 */
    --surface-3: rgba(11, 15, 31, 0.96);   /* 弹窗深空底 */
    --hairline: rgba(165, 180, 252, 0.22); /* 细分隔线 */
    --hairline-strong: rgba(231, 196, 122, 0.45); /* 金色虚线描边 */

    /* 星辉装饰 */
    --star-color: var(--theme-color-1);
    --star-glow: color-mix(in srgb, var(--theme-color-1) 55%, transparent);

    --ui-color-main: var(--surface-1);
    --ui-color-sec: var(--surface-2);
    --text-color-main: var(--SmartThemeBodyColor);
    --text-color-sec: var(--SmartThemeEmColor);
    --top-bar-color: var(--SmartThemeBorderColor);
    --top-bar-underline-color: var(--theme-color-1);
    --top-bar-icon-color: var(--text-color-main);
    --code-color: var(--SmartThemeShadowColor);
    --chat-background-color: transparent;
    --user-color: rgba(0, 0, 0, 0);
    --char-color: rgba(0, 0, 0, 0);
    --mes-width: 100%;
    --mes-block-width: 98%;
    --box-border-radius: 0px;
    --top-distance: 0px;
    --bottom-distance: 0px;
    --chat-send-spacing: 0px;
    --leftRight-chat-spacing: 0px;
    --scroll-width: 5px;
    --icon-size: var(--mainFontSize);
    --border-radius-small: 5px;
    --border-radius-medium: 10px;
    --spacing-long: 10px;
    --spacing-short: 5px;
    --topBarIconSize: calc(var(--icon-size) * 2);
    --slider-icon: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 32 32"><text x="50%" y="50%" dominant-baseline="central" text-anchor="middle" font-size="30" fill="%23E7C47A">✦</text></svg>');
    --slider-size: 24px;
    --gradient-main: linear-gradient(
        135deg,
        var(--theme-color-1) 30%,
        color-mix(in srgb, var(--theme-color-1) 50%, var(--theme-color-2) 50%) 50%,
        var(--theme-color-2) 70%
    );
}

/* ==========================================================================
   3. 滚动条样式
   ========================================================================== */
::-webkit-scrollbar {
    width: var(--scroll-width);
}
::-webkit-scrollbar:horizontal {
    height: var(--scroll-width);
}
::-webkit-scrollbar-track {
    background: transparent;
}
::-webkit-scrollbar-thumb:vertical,
::-webkit-scrollbar-thumb:horizontal {
    background-color: color-mix(in srgb, var(--theme-color-1) 60%, transparent);
    box-shadow: none;
    border: 0;
    border-radius: 99px;
}
::-webkit-scrollbar-thumb:hover {
    background-color: var(--theme-color-1);
}

/* ==========================================================================
   4. 通用 UI 组件 (Input, Button, Checkbox, Slider)
   ========================================================================== */
input[type="text"],
input[type="number"],
input[type="switch"],
input:not([type]),
textarea:not([type="search"]) {
    background-color: var(--ui-color-sec) !important;
    border: 1px solid var(--hairline) !important;
    color: var(--text-color-main) !important;
}
input[type="text"]:focus,
input[type="number"]:focus,
input[type="switch"]:focus,
input:not([type]):focus,
textarea:not([type="search"]):focus {
    border: 1px solid var(--theme-color-1) !important;
}
textarea[type="search"] {
    background-color: transparent !important;
    border: none !important;
}
.text_pole:not(.objective-task) {
    background-color: var(--ui-color-sec);
    border: 1px solid var(--hairline);
    color: var(--text-color-main);
}
.menu_button:not(.mes_edit_buttons *) {
    background-color: var(--ui-color-sec);
    border-color: var(--hairline);
    color: var(--text-color-main);
}
.menu_button_icon i {
    font-size: calc(var(--icon-size) * 0.8);
}
#delete_button,
#dialogue_del_mes_ok,
#dialogue_popup_ok,
#bulk_tag_popup_reset,
#bulk_tag_popup_remove_mutual,
.mes_edit_cancel.menu_button,
.menu_button.popup-button-ok,
.redWarningBG {
    background-color: var(--crimson70a) !important;
    color: var(--white100) !important;
}
.mes_edit_buttons .menu_button,
#mes_edit_done,
#mes_edit_cancel,
#mes_edit_clone {
    border-style: dashed !important;
    border-width: 1px !important;
    border-color: var(--theme-color-2) !important;
    background-color: var(--ui-color-main) !important;
    color: var(--text-color-sec) !important;
}
.mes_button,
.mes_edit_buttons,
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt span span span {
    filter: none !important;
}

select {
    background-color: var(--ui-color-sec) !important;
    color: var(--text-color-main);
    border: 1px solid var(--hairline) !important;
    margin: calc(var(--mainFontSize) * 0.3) 0 !important;
}
select option:not(:checked) { color: var(--text-color-sec); }
select option:checked {
    color: var(--surface-3);
    background-color: var(--theme-color-1) !important;
}
select option { background-color: var(--surface-3) !important; }

input[type="checkbox"] {
    width: calc(var(--mainFontSize) * 0.9);
    height: calc(var(--mainFontSize) * 0.9);
    border: none;
    outline: none;
    background-color: var(--surface-2);
    filter: none;
    box-shadow: 0 0 0 1px var(--text-color-sec);
    transform: translateY(0);
    margin-left: 1px;
}
input[type="checkbox"]::before {
    box-shadow: inset 1em 1em var(--theme-color-1);
}
input[type="checkbox"].del_checkbox { margin-right: 0; }

input[type="range"] {
    box-shadow: none;
    background-color: var(--ui-color-sec) !important;
}
input[type="range"]:hover {
    background-color: color-mix(in srgb, var(--ui-color-sec) 60%, var(--theme-color-1) 40%) !important;
}
input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: var(--slider-size);
    height: var(--slider-size);
    background-image: var(--slider-icon);
    background-repeat: no-repeat;
    background-position: center;
    background-size: contain;
    background-color: transparent;
    box-shadow: none;
    border: none;
    cursor: pointer;
    transition: transform 0.1s;
}
input[type="range"]::-webkit-slider-thumb:hover { transform: scale(1.2); }
.neo-range-slider { box-shadow: inset 0 0 0 3px rgba(0, 0, 0, 0.35) !important; }
.range-block { margin: calc(var(--mainFontSize) * 0.6) 0; }
.range-block-counter { margin-left: 20px; }

.fa-solid:not(#load-spinner) {
    font-size: var(--icon-size);
    text-shadow: none !important;
}
.fa-fw:not(#qr--modal-icon) { width: auto; }

/* ==========================================================================
   5. 标题与排版
   ========================================================================== */
.standoutHeader strong,
#right-nav-panel h2,
#Backgrounds h3,
.drawer-content > h3,
.drawer-content .flex-container h3:first-of-type:not(#Backgrounds .textAlignCenter),
.drawer-content .flex-container .flex-container h3:first-of-type,
.popup h3:not(dialog *)::before {
    font-size: calc(var(--mainFontSize) * 1.2);
    color: var(--text-color-main);
    letter-spacing: 0.1em;
    white-space: nowrap;
    line-height: 2;
}

.standoutHeader strong::before,
#right-nav-panel h2::before,
#Backgrounds h3::before,
.drawer-content > h3::before,
.drawer-content .flex-container h3:first-of-type:not(#Backgrounds .textAlignCenter)::before,
.drawer-content .flex-container .flex-container h3:first-of-type::before,
.popup h3:not(dialog *)::before {
    content: "✦";
    position: relative;
    background: var(--gradient-main);
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
    font-size: calc(var(--mainFontSize) * 1.3);
    text-shadow: none;
    padding-bottom: 0.5px;
}
.standoutHeader:not(h4),
#rm_PinAndTabs,
#top-settings-holder .drawer:not(:first-child):not(:last-child) .drawer-content .alignItemsBaseline.wide100p,
#rm_api_block .flex-container.alignItemsBaseline,
#title_api,
#AdvancedFormatting .flex-container.alignItemsBaseline:not(h3),
#WorldInfo .alignitemscenter:not(#world_popup *),
#user-settings-block div[name="userSettingsRowOne"],
#rm_extensions_block .alignitemscenter.flex-container.wide100p:not(.justifyCenter) {
    background-image: none;
    border-radius: 0;
    border: none;
    border-bottom: 1px solid var(--hairline);
    margin-bottom: calc(var(--mainFontSize) * 0.4);
    padding-bottom: calc(var(--mainFontSize) * 0.2);
}
.drawer-content .alignItemsBaseline { align-items: center !important; }
#title_api { padding-bottom: 0; }
#title_api::before,
#Backgrounds h3.margin0.flex2::before,
#rm_extensions_block .margin0.flex1::before,
#rm_button_selected_ch h2::before {
    margin-right: calc(var(--mainFontSize) * 0.4);
}

/* ==========================================================================
   6. 容器与面板基础
   ========================================================================== */
#left-nav-panel,
#right-nav-panel,
#chat,
.drawer-content,
#Backgrounds {
    padding: var(--spacing-long);
    background-color: var(--ui-color-main);
    border-radius: var(--box-border-radius);
    border: none;
}
.inline-drawer-header,
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#top-settings-holder h4:not(#ai-config-button *):not(#rightNavHolder *) {
    border-width: 0 0 0 3px !important;
    border-color: transparent !important;
    border-style: solid;
    border-radius: 0;
    background-image: none !important;
    padding-left: 7px;
    border-image: linear-gradient(to bottom, transparent 25%, var(--theme-color-1) 25%, var(--theme-color-1) 75%, transparent 75%) 1 100%;
}
.inline-drawer-icon { font-size: var(--icon-size); }
.list-group,
.options-content {
    border: 1px dashed var(--hairline) !important;
    border-radius: 15px !important;
    background-color: var(--surface-2) !important;
    box-shadow: none !important;
}
#options {
    background-color: transparent !important;
    padding: 0;
    box-shadow: none !important;
}
code {
    margin: 0;
    border: none;
    background-color: var(--code-color);
    color: var(--text-color-main);
}
body[data-stscript-style] .hljs.language-stscript,
.hljs,
.custom-mermaid {
    background: var(--code-color);
}

/* ==========================================================================
   7. 弹窗 (Popup) 统一样式
   ========================================================================== */
#character_popup,
#dialogue_popup,
.draggable,
#select_chat_popup,
.popup:not(.transparent_dialogue_popup) {
    padding: 10px 10px 35px 10px !important;
    background-color: var(--surface-3) !important;
    border-radius: 15px !important;
    border: 2px dashed var(--hairline-strong) !important;
    overflow: visible !important;
    background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='400' height='30'><text x='50%' y='50%' dominant-baseline='middle' text-anchor='middle' fill='%23E7C47A' font-size='14' font-family='sans-serif' opacity='0.85'>⊹ ★ ┈┈ 𓏴 𝓢𝓱𝓲𝓷𝓲𝓷 𝓢𝓽𝓪𝓻𝓼 𓏴 ★ ┈┈ ⊹</text></svg>") !important;
    background-repeat: no-repeat !important;
    background-position: bottom 0px center !important;
    background-size: 100% auto !important;
}
#character_popup::before, #dialogue_popup::before, .draggable::before, #select_chat_popup::before, .popup:not(.transparent_dialogue_popup)::before {
    content: "★";
    position: absolute;
    top: -35px; right: -15px;
    font-size: 50px;
    color: var(--star-color);
    pointer-events: none;
    z-index: 100;
    text-shadow: 0 0 12px var(--star-glow);
    transform: rotate(15deg);
}
#character_popup::after, #dialogue_popup::after, .draggable::after, #select_chat_popup::after, .popup:not(.transparent_dialogue_popup)::after {
    content: "★";
    position: absolute;
    top: -5px; right: 20px;
    font-size: 24px;
    color: var(--star-color);
    pointer-events: none;
    z-index: 100;
    text-shadow: 0 0 8px var(--star-glow);
    transform: rotate(-10deg);
}
.popup .menu_button, .popup .list-group-item, .popup .option-label { color: var(--text-color-main) !important; }
.popup .menu_button {
    background-color: var(--surface-2) !important;
    border: 1px dashed var(--hairline-strong) !important;
    border-radius: 12px !important;
    margin-top: 15px !important;
    padding: 6px 15px !important;
    box-shadow: none !important;
    transition: background-color 0.2s ease, color 0.2s ease, border-color 0.2s ease;
}
.popup .menu_button:hover {
    background-color: var(--theme-color-1) !important;
    color: var(--surface-3) !important;
    border-style: solid !important;
}
#dialogue_popup .menu_button,
#dialogue_del_mes .menu_button {
    background-color: var(--surface-2) !important;
    border: 1px dashed var(--hairline) !important;
    color: var(--text-color-main) !important;
    border-radius: 8px !important;
}
#dialogue_popup .menu_button:hover,
#dialogue_del_mes .menu_button:hover {
    border-color: var(--theme-color-1) !important;
    background-color: color-mix(in srgb, var(--theme-color-1) 18%, var(--surface-2)) !important;
}
#select_chat_popup .menu_button {
    background-color: var(--surface-2) !important;
    border: 1px dashed var(--hairline) !important;
    border-radius: 8px !important;
    color: var(--text-color-main) !important;
    box-shadow: none !important;
}
#select_chat_popup .menu_button:hover {
    border-color: var(--theme-color-1) !important;
    background-color: color-mix(in srgb, var(--theme-color-1) 18%, var(--surface-2)) !important;
}

#dialogue_popup_text { padding: 0 var(--spacing-long) 0 0; }

/* ==========================================================================
   8. 顶栏
   ========================================================================== */
:root {
    --top-bar-width: 93%;
}

body.no-blur #top-bar,
#top-bar {
    background-color: var(--surface-3) !important;
    margin: 10px auto !important;
    width: var(--top-bar-width) !important;
    max-width: none !important;
    border-radius: 7px !important;
    border: 1px solid var(--hairline) !important;
    box-shadow: 0 4px 18px rgba(0, 0, 0, 0.45) !important;
}
body.waifuMode #top-bar { border: none; }

#top-settings-holder {
    top: var(--top-distance);
    box-shadow: none !important;
    background: transparent;
    padding-top: 20px !important;
    display: flex !important;
    justify-content: center !important;
    gap: 6px !important;
}
#top-settings-holder > :first-child { border-radius: 20px 0 0 20px; }
#top-settings-holder > :last-child { border-radius: 0 20px 20px 0; }
#top-settings-holder .drawer-content { margin-top: 9px !important; }

.drawer {
    color: var(--top-bar-icon-color);
    background-color: transparent;
    padding: 0 2px !important;
    margin: 0 !important;
    width: 35px !important;
    min-width: unset !important;
    flex: 0 0 auto !important;
    display: flex;
    justify-content: center;
    align-items: center;
}
.drawer:has(.openDrawer) {
    background-color: rgba(165, 180, 252, 0.15);
    border-radius: 10px;
}
.drawer-icon {
    opacity: 0.55;
    font-size: calc(var(--icon-size) * 1.1);
    text-shadow: none !important;
    transition: opacity 0.2s ease;
}
.drawer-icon:hover, .drawer-icon.openIcon {
    opacity: 1;
    background: var(--gradient-main);
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
}

.drawer-content {
    box-shadow: 0 6px 16px -6px rgba(0, 0, 0, 0.6);
    border-radius: 0 0 var(--border-radius-small) var(--border-radius-small);
    border-bottom: 1px solid var(--top-bar-underline-color);
}
.drawer-content:not(#left-nav-panel):not(#right-nav-panel) {
    border-radius: 0 0 var(--border-radius-small) var(--border-radius-small);
}

#top-settings-holder .drawer-content,
#top-settings-holder .drawer-content .list-group,
#top-settings-holder .drawer-content .options-content {
    background-color: var(--surface-3) !important;
}
#top-settings-holder .drawer-content .menu_button,
#top-settings-holder .drawer-content input[type="text"],
#top-settings-holder .drawer-content .text_pole,
#top-settings-holder .drawer-content textarea,
#top-settings-holder .drawer-content select {
    background-color: var(--surface-2) !important;
    border: 1px dashed var(--hairline) !important;
    color: var(--text-color-main) !important;
}
#top-settings-holder .drawer-content .menu_button:hover,
#top-settings-holder .drawer-content input:hover {
    border-color: var(--theme-color-1) !important;
}
#top-settings-holder .drawer-content input[type="number"] {
    background-color: var(--surface-2) !important;
    border: 1px solid var(--hairline) !important;
    color: var(--text-color-main) !important;
}

/* --- 图标自定义 --- */
#leftNavDrawerIcon::before, #rightNavDrawerIcon::before, #sys-settings-button .drawer-icon::before, #user-settings-button .drawer-icon::before, #backgrounds-button .drawer-icon::before, #advanced-formatting-button .drawer-icon::before, #WI-SP-button .drawer-icon::before, #extensions-settings-button .drawer-icon::before, #persona-management-button .drawer-icon::before, #logo_block .drawer-icon::before {
    background-image: none !important;
    background: none !important;
    font-size: 1.5em !important;
    display: flex !important;
    align-items: center;
    justify-content: center;
    width: 100%; height: 100%;
    color: var(--top-bar-icon-color);
    opacity: 1 !important;
}
#leftNavDrawerIcon::before { content: "⭐︎" !important; }
#sys-settings-button .drawer-icon::before { content: "🎞︎" !important; }
#advanced-formatting-button .drawer-icon::before { content: "☪︎" !important; }
#WI-SP-button .drawer-icon::before { content: "✡︎" !important; }
#user-settings-button .drawer-icon::before { content: "☄︎" !important; }
#backgrounds-button .drawer-icon::before { content: "📷" !important; }
#extensions-settings-button .drawer-icon::before { content: "⚙" !important; }
#persona-management-button .drawer-icon::before { content: "♛" !important; }
#rightNavDrawerIcon::before { content: "♚" !important; }

/* ==========================================================================
   9. 左/右侧面板 (Side Panels)
   ========================================================================== */
#left-nav-panel, #right-nav-panel {
    top: var(--top-distance);
    height: 100dvh !important;
    max-height: calc(100dvh - var(--top-distance) - var(--bottom-distance) - 1px);
}
#right-nav-panel {
    width: calc((100vw - var(--sheldWidth)) / 2 - var(--leftRight-chat-spacing));
}
#left-nav-panel {
    width: calc((100vw - var(--sheldWidth)) / 2 - var(--leftRight-chat-spacing));
    padding-right: 0;
}

#right-nav-panel input[type="text"],
#right-nav-panel input[type="number"],
#right-nav-panel textarea,
#right-nav-panel .menu_button,
#right-nav-panel select,
.drawer-content input[type="text"],
.drawer-content input[type="number"],
.drawer-content textarea,
.drawer-content .menu_button,
.drawer-content select {
    background-color: var(--surface-2) !important;
    border: 1px dashed var(--hairline) !important;
    border-radius: 8px !important;
    color: var(--text-color-main) !important;
    box-shadow: none !important;
}
#right-nav-panel input:focus,
#right-nav-panel textarea:focus,
#right-nav-panel .menu_button:hover,
#right-nav-panel select:hover,
.drawer-content input:focus,
.drawer-content textarea:focus,
.drawer-content .menu_button:hover,
.drawer-content select:hover {
    border-color: var(--theme-color-1) !important;
    background-color: color-mix(in srgb, var(--theme-color-1) 12%, var(--surface-2)) !important;
    border-style: dashed !important;
}
#right-nav-panel hr:first-of-type { display: none; }
#CharListButtonAndHotSwaps { margin-bottom: calc(var(--mainFontSize) * 0.8); }
label[for="char-management-dropdown"] { width: 100%; }
#avatar_div { flex-direction: column; }
#avatar_controls { align-items: center; }
.character_select { margin-top: calc(var(--mainFontSize) * 0.8); }
.character_select.is_fav .avatar { outline: 2px solid var(--theme-color-1); }
.character_select.is_fav .ch_name { color: var(--theme-color-1); }
.tag.excluded::after { font-size: calc(var(--icon-size) * 2); }
.tag.actionable { font-size: calc(var(--icon-size) * 1); min-height: calc(var(--icon-size) * 2); min-width: calc(var(--icon-size) * 2); }

/* 收藏栏拖动 */
#HotSwapWrapper { overflow: hidden; }
#HotSwapWrapper > div {
    overflow: auto hidden;
    flex-wrap: nowrap;
    height: calc(var(--avatar-base-height) + var(--scroll-width) + 10px);
    max-height: calc(var(--avatar-base-height) * 2);
}
body.big-avatars #HotSwapWrapper > div {
    height: calc(var(--avatar-base-height) * var(--big-avatar-height-factor) + var(--scroll-width) + 10px);
