    border: 1px solid var(--hairline) !important;
    border-radius: 10px !important;
    font-size: calc(var(--mainFontSize) * 0.9);
    padding: 4px 12px !important;
    box-shadow: 0 2px 6px rgba(0,0,0,0.35) !important;
    margin: 0 !important;
    transition: background-color 0.2s ease, border-color 0.2s ease;
}

#qr--bar > .qr--buttons .qr--button:hover,
#qr--popout > .qr--body > .qr--buttons .qr--button:hover {
    background-color: color-mix(in srgb, var(--theme-color-1) 18%, var(--surface-2)) !important;
    border-color: var(--theme-color-1) !important;
}
#qr--popoutTrigger { background-color: transparent; border: none; }
.popup:has(#qr--modalEditor) .popup-content > #qr--modalEditor > #qr--main > .qr--modal-messageContainer > #qr--modal-messageHolder > #qr--modal-message {
    color: var(--text-color-main) !important;
}
.popup:has(#qr--modalEditor) .popup-content #qr--modal-message::selection {
    color: var(--text-color-main) !important;
}
@supports (color: rgb(from white r g b / 0.25)) {
    .popup:has(#qr--modalEditor) .popup-content #qr--modal-message::selection {
        background-color: rgb(from var(--theme-color-1) r g b / 0.25) !important;
    }
