/* ==========================================================================
   13. 移动端适配
   ========================================================================== */
@supports (-webkit-touch-callout: none) {
    .standoutHeader strong::before, #right-nav-panel h2::before, #Backgrounds h3::before, .drawer-content > h3::before,
    .drawer-content .flex-container h3:first-of-type:not(#Backgrounds .textAlignCenter)::before,
    .drawer-content .flex-container .flex-container h3:first-of-type::before, .popup h3:not(dialog *)::before {
        font-size: calc(var(--mainFontSize) * 1.7);
    }
    #chat { padding-right: var(--scroll-width); }
    #world_popup { margin-top: 0; width: 100%; }
}

@media screen and (max-width: 1000px) {
    #left-nav-panel, #right-nav-panel, .drawer-content { margin-top: var(--top-distance); }
    #left-nav-panel, #right-nav-panel {
        height: calc(100dvh - 45px) !important;
        max-height: calc(100dvh - var(--topBarBlockSize)) !important;
        border-radius: 0 0 var(--border-radius-small) var(--border-radius-small);
    }
    .world_entry_form .inline-drawer-header {
        border-width: 0 0 0 3px !important;
        border-color: var(--theme-color-1) !important;
        border-style: solid;
        border-image: none;
    }
}

@supports (-webkit-touch-callout: none) {
    @media screen and (min-width: 1000px) {
        #character_popup, #world_popup, .drawer-content { margin-top: 0px; }
        #top-settings-holder .drawer .drawer-content { right: 0; left: 0; width: var(--sheldWidth); margin-top: 3px !important; }
        #left-nav-panel, #right-nav-panel {
            margin: 0 auto;
            top: calc(var(--topBarBlockSize) + var(--top-distance));
            max-height: calc(100dvh - var(--topBarBlockSize) - var(--bottomFormBlockSize));
            border-radius: 0 0 var(--border-radius-small) var(--border-radius-small);
            border-bottom: 1px solid var(--top-bar-underline-color);
        }
        #left-nav-panel { padding-right: var(--spacing-long); }
        .fillLeft .scrollableInner { padding-right: 0.5em; }
    }
}

#extensionTopBar {
    margin: 10px 10px 0px 0px !important;
}

/* ==========================================================================
   14. 无障碍 / 性能：尊重 prefers-reduced-motion
   ========================================================================== */
@media (prefers-reduced-motion: reduce) {
    *, *::before, *::after {
        animation-duration: 0.001ms !important;
        animation-iteration-count: 1 !important;
        transition-duration: 0.001ms !important;
    }
}
